body.script:
test(function() {
  const el2 = document.getElementById('two');
  const el3 = document.getElementById('three');

  // Perform the DOM manipulation
  el2.parentNode.insertBefore(el3.nextSibling, el2);

  // Check styles
  // #two is no longer :first-child, so it should not be red
  assert_not_background_color(el2, RED, '#two should not be red');
  // #three is now :last-child, so it should be lime
  assert_background_color(el3, LIME, '#three should be lime');
}, "Dynamic updating of :first-child and :last-child");
